basic_try_except.example:
try:
    result = tool_function(params)
except ValueError as e:
    print(f'Validation error: {e}')
    return None
except Exception as e:
    print(f'Unexpected error: {e}')
    raise

retry_logic.example:
from time import sleep
for attempt in range(3):
    try:
        data = fetch_data(params)
        break
    except TimeoutError:
        if attempt < 2:
            sleep(2 ** attempt)
        else:
            raise

graceful_degradation.example:
results = {}
for attr_name, func in extractors.items():
    try:
        results[attr_name] = func(watershed)
    except Exception as e:
        print(f'Failed to extract {attr_name}: {e}')
        results[attr_name] = None

